import pandas as pd
from sentence_transformers import SentenceTransformer, util
import torch

# Set up the model and database
model = SentenceTransformer('paraphrase-multilingual-mpnet-base-v2')
db = 'company_documents.db'

# Load company documents into vector database
def load_documents(db):
    conn = sqlite3.connect(db)
    df = pd.read_sql_query("SELECT * FROM documents", conn)
    embeddings = model.encode(df['text'])
    return df, embeddings

# Retrieve relevant context based on user query
def retrieve_context(query, db, model):
    query_embedding = model.encode(query)
    similarities = util.cos_sim(query_embedding, model.encode(df['text']))
    indices = torch.topk(similarities, 10).indices
    return df.iloc[indices]

# Generate response using LLM
def generate_response(retrieved_docs, prompt):
    output = model(prompt + ' '.join(retrieved_docs['title']))
    return output

# Main function to integrate RAG system
def rag_system(db, model):
    query = input("Enter your query: ")
    retrieved_docs = retrieve_context(query, db, model)
    prompt = input("Provide a brief context for the LLM: ")
    response = generate_response(retrieved_docs, prompt)
    return response

# Load documents and start RAG system
df, embeddings = load_documents(db)
print(rag_system(db, model))